#include <stdio.h>
#include <stdlib.h>

int factorial(int n) {
    if (n == 0) return 1;
    return n * factorial(n-1);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int prefix[m];
        for (int i = 0; i < m; i++) {
            scanf("%d", &prefix[i]);
        }
        int remaining = n - m;
        printf("%d\n", factorial(remaining));
    }
    return 0;
}

